using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Shared state for the note-taking tool ---
var notebook = new ResearchNotebook();

// --- Build the IChatClient through the MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools the agent can call ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return SearchWebAsync(query);
        },
        new AIFunctionFactoryOptions
        {
            Name = "search_web",
            Description = "Searches the web for a query and returns a list of result snippets. Use this to find information about a topic.",
        }),

    AIFunctionFactory.Create(
        (
            [Description("A short title for the note")] string title,
            [Description("The detailed content of the note")] string content
        ) =>
        {
            notebook.Add(title, content);
            return $"Note saved: \"{title}\" ({content.Length} chars)";
        },
        new AIFunctionFactoryOptions
        {
            Name = "take_note",
            Description = "Saves a research note with a title and detailed content. Use this to record important findings during research.",
        }),

    AIFunctionFactory.Create(
        () =>
        {
            if (notebook.Notes.Count == 0)
                return "No notes have been taken yet.";

            return string.Join("\n\n", notebook.Notes.Select((n, i) =>
                $"[{i + 1}] {n.Title}\n{n.Content}"));
        },
        new AIFunctionFactoryOptions
        {
            Name = "get_notes",
            Description = "Retrieves all research notes taken so far. Use this to review findings before writing a summary.",
        }),
};

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic, you must:
        1. Search the web multiple times with different queries to gather diverse information.
        2. Take notes on the most important findings from each search.
        3. Review your notes, then produce a well-structured summary of your research.

        Always search at least 3 times with varied queries before summarizing.
        Always take notes on key findings before writing your final summary.
        Your final summary should be thorough and cite the information you found.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or       ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();
    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"Researching: {topic}...");
    Console.ResetColor();

    try
    {
        var runOptions = new ChatClientAgentRunOptions(new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
        });

        await foreach (var update in agent.RunStreamingAsync(
            $"Research this topic thoroughly and provide a comprehensive summary: {topic}",
            options: runOptions))
        {
            if (!string.IsNullOrEmpty(update.Text))
            {
                Console.Write(update.Text);
            }
        }

        Console.WriteLine();
        Console.WriteLine();

        if (notebook.Notes.Count > 0)
        {
            Console.ForegroundColor = ConsoleColor.Green;
            Console.WriteLine($"📝 {notebook.Notes.Count} research note(s) were taken during this session.");
            Console.ResetColor();
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");
return;

// --- Web search implementation ---
// Uses Bing search page scraping as a lightweight demo.
// For production, replace with Bing Search API, Google Custom Search, or similar.
static async Task<string> SearchWebAsync(string query)
{
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine($"  🔎 Searching: \"{query}\"");
    Console.ResetColor();

    try
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
        var html = await http.GetStringAsync(url);

        var snippets = ExtractSnippets(html);
        if (snippets.Count == 0)
            return $"No results found for \"{query}\".";

        return string.Join("\n\n", snippets.Take(5).Select((s, i) =>
            $"Result {i + 1}:\nTitle: {s.Title}\nSnippet: {s.Snippet}"));
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

static List<SearchResult> ExtractSnippets(string html)
{
    var results = new List<SearchResult>();

    // Parse DuckDuckGo HTML results
    var titlePattern = "class=\"result__a\"";
    var snippetPattern = "class=\"result__snippet\"";

    var pos = 0;
    while (results.Count < 5)
    {
        var titleStart = html.IndexOf(titlePattern, pos, StringComparison.Ordinal);
        if (titleStart < 0) break;

        var title = ExtractTagContent(html, titleStart);
        var snippetStart = html.IndexOf(snippetPattern, titleStart, StringComparison.Ordinal);
        var snippet = snippetStart >= 0 ? ExtractTagContent(html, snippetStart) : "";

        if (!string.IsNullOrWhiteSpace(title))
        {
            results.Add(new SearchResult(
                StripHtml(title).Trim(),
                StripHtml(snippet).Trim()));
        }

        pos = snippetStart >= 0 ? snippetStart + 1 : titleStart + 1;
    }

    return results;
}

static string ExtractTagContent(string html, int classAttrPos)
{
    // Find the > that closes the tag containing this class attribute
    var tagClose = html.IndexOf('>', classAttrPos);
    if (tagClose < 0) return "";

    // Find the next closing tag
    var contentStart = tagClose + 1;
    var contentEnd = html.IndexOf('<', contentStart);
    if (contentEnd < 0) return "";

    // For tags with nested content, grab more
    var depth = 1;
    var i = contentEnd;
    while (i < html.Length && depth > 0)
    {
        if (html[i] == '<')
        {
            if (i + 1 < html.Length && html[i + 1] == '/')
                depth--;
            else if (i + 1 < html.Length && html[i + 1] != '!')
                depth++;
        }
        i++;
        // Skip to end of tag
        while (i < html.Length && html[i - 1] != '>') i++;
    }

    return html[contentStart..i];
}

static string StripHtml(string html)
{
    var result = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", " ");
    result = WebUtility.HtmlDecode(result);
    return System.Text.RegularExpressions.Regex.Replace(result, @"\s+", " ");
}

// --- Supporting types ---
record SearchResult(string Title, string Snippet);

record ResearchNote(string Title, string Content, DateTime Timestamp);

class ResearchNotebook
{
    public List<ResearchNote> Notes { get; } = [];

    public void Add(string title, string content)
    {
        Notes.Add(new ResearchNote(title, content, DateTime.UtcNow));
        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine($"  📝 Note taken: \"{title}\"");
        Console.ResetColor();
    }

    public void Clear() => Notes.Clear();
}

