using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Shared state for the note-taking tool ---
var notebook = new ResearchNotebook();

// --- Build the IChatClient through the MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools the agent can call ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return SearchWebAsync(query);
        },
        new AIFunctionFactoryOptions
        {
            Name = "search_web",
            Description = "Searches the web for a query and returns a list of result snippets. Use this to find information about a topic.",
        }),

    AIFunctionFactory.Create(
        (
            [Description("A short title for the note")] string title,
            [Description("The detailed content of the note")] string content
        ) =>
        {
            notebook.Add(title, content);
            return $"Note saved: \"{title}\" ({content.Length} chars)";
        },
        new AIFunctionFactoryOptions
        {
            Name = "take_note",
            Description = "Saves a research note with a title and detailed content. Use this to record important findings during research.",
        }),

    AIFunctionFactory.Create(
        () =>
        {
            if (notebook.Notes.Count == 0)
                return "No notes have been taken yet.";

            return string.Join("\n\n", notebook.Notes.Select((n, i) =>
                $"[{i + 1}] {n.Title}\n{n.Content}"));
        },
        new AIFunctionFactoryOptions
        {
            Name = "get_notes",
            Description = "Retrieves all research notes taken so far. Use this to review findings before writing a summary.",
        }),
};

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic, you must:
        1. Search the web multiple times with different queries to gather diverse information.
        2. Take notes on the most important findings from each search.
        3. Review your notes, then produce a well-structured summary of your research.

        Always search at least 3 times with varied queries before summarizing.
        Always take notes on key findings before writing your final summary.
        Your final summary should be thorough and cite the information you found.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or       ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();
    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"Researching: {topic}...");
    Console.ResetColor();

    try
    {
        var runOptions = new ChatClientAgentRunOptions(new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
        });

        await foreach (var update in agent.RunStreamingAsync(
            $"Research this topic thoroughly and provide a comprehensive summary: {topic}",
            options: runOptions))
        {
            if (!string.IsNullOrEmpty(update.Text))
            {
                Console.Write(update.Text);
            }
        }

        Console.WriteLine();
        Console.WriteLine();

        if (notebook.Notes.Count > 0)
        {
            Console.ForegroundColor = ConsoleColor.Green;
            Console.WriteLine($"📝 {notebook.Notes.Count} research note(s) were taken during this session.");
            Console.ResetColor();
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");
return;

